mapper.select:
SELECT 
    measured_at AS date
    ,ROUND(raw_val, 3) AS raw
FROM data_${params.placeCode}
WHERE 
	sensor_id = #{params.sensorId}
	AND raw_val != 0
	AND used = true 
ORDER BY
    date;

SELECT 
	COUNT(*) 
FROM data_${params.placeCode} 
WHERE 
	sensor_id = #{params.sensorId}
	AND used = true
